#include <iostream>
#include <algorithm>
using namespace std;
int a[100005];
int n,k;
bool check(int x)
{
    int sum=0;
    for(int i=1;i<=n;i++)
    {
        sum=sum+a[i]/x;
    }
    if(sum>=k)
    {
        return true;
    }
    else
    {
        return false;
    }
}
int main()
{
    cin>>n>>k;
    for(int i=1;i<=n;i++)
    {
        cin>>a[i];
    }
    int l=1,r=100000000,mid,ans=0;
    while(l<=r)
    {
        mid=(l+r)/2;
        if(check(mid))
        {
            l=mid+1;
            ans=mid;
        }
        else
        {
            r=mid-1;
        }
    }
    cout<<ans;  
}
